import { Routes, Route, useLocation } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import Home from './pages/Home';
import About from './pages/About';
import RegisteredCandidates from './pages/RegisteredCandidates';
import Registration from './pages/Registration';
import Contact from './pages/Contact';
import Viewjobs from './pages/Viewjobs';
import Login from './pages/Login';
import Signup from './pages/Signup';
import AdminPanel from './pages/AdminPanel';
import Services from './pages/Services';
import PrivateRoute from './components/PrivateRoute';

const PageWrapper = ({ children }) => {
    return (
        <motion.div
            initial={{ opacity: 0, x: 20 }}
            animate={{ opacity: 1, x: 0 }}
            exit={{ opacity: 0, x: -20 }}
            transition={{ duration: 0.3, ease: 'easeInOut' }}
        >
            {children}
        </motion.div>
    );
};

const AppRoutes = () => {
    console.log('AppRoutes rendering with AnimatePresence');
    const location = useLocation();

    return (
        <AnimatePresence mode="wait">
            <Routes location={location} key={location.pathname}>
                <Route path="/" element={<PageWrapper><Home /></PageWrapper>} />
                <Route path="/about" element={<PageWrapper><About /></PageWrapper>} />
                <Route path="/registered-candidates" element={
                    <PrivateRoute>
                        <PageWrapper><RegisteredCandidates /></PageWrapper>
                    </PrivateRoute>
                } />
                <Route path="/postres" element={<PageWrapper><Registration /></PageWrapper>} />
                <Route path="/contact" element={<PageWrapper><Contact /></PageWrapper>} />
                <Route path="/services" element={<PageWrapper><Services /></PageWrapper>} />
                <Route path="/viewjobs" element={<PageWrapper><Viewjobs /></PageWrapper>} />
                <Route path="/login" element={<PageWrapper><Login /></PageWrapper>} />
                <Route path="/signup" element={<PageWrapper><Signup /></PageWrapper>} />
                <Route path="/admin-panel" element={
                    <PrivateRoute>
                        <PageWrapper><AdminPanel /></PageWrapper>
                    </PrivateRoute>
                } />
            </Routes>
        </AnimatePresence>
    );
};

export default AppRoutes;

import React, { useState, useEffect } from 'react';
import { X, Upload, Image as ImageIcon, Type, AlignLeft, Hash } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { useDispatch } from 'react-redux';
import { createSlide } from '../../store/slices/carouselSlice';

const CarouselModal = ({ isOpen, onClose }) => {
    const dispatch = useDispatch();
    const [formData, setFormData] = useState({
        title: '',
        subtitle: '',
        order: 0,
        url: ''
    });
    const [preview, setPreview] = useState(null);
    const [fileType, setFileType] = useState('image'); // 'image' or 'video'

    const handleFileChange = (e) => {
        const file = e.target.files[0];
        if (file) {
            setFileType(file.type.startsWith('video') ? 'video' : 'image');
            const reader = new FileReader();
            reader.onloadend = () => {
                setPreview(reader.result);
                setFormData({ ...formData, url: reader.result });
            };
            reader.readAsDataURL(file);
        }
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        if (!formData.url) {
            alert('Please select a file');
            return;
        }
        await dispatch(createSlide(formData));
        onClose();
        setFormData({ title: '', subtitle: '', order: 0, url: '' });
        setPreview(null);
    };

    if (!isOpen) return null;

    return (
        <AnimatePresence>
            <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
                <motion.div 
                    initial={{ opacity: 0, scale: 0.9, y: 20 }}
                    animate={{ opacity: 1, scale: 1, y: 0 }}
                    exit={{ opacity: 0, scale: 0.9, y: 20 }}
                    className="bg-white rounded-[2.5rem] p-8 max-w-xl w-full relative shadow-2xl overflow-hidden"
                >
                    <div className="flex justify-between items-center mb-6">
                        <div className="flex items-center gap-3">
                            <div className="p-2 bg-emerald-50 text-emerald-600 rounded-xl">
                                <ImageIcon className="w-6 h-6" />
                            </div>
                            <h2 className="text-2xl font-black text-slate-900 uppercase tracking-tight">Add Carousel Slide</h2>
                        </div>
                        <button onClick={onClose} className="p-2 hover:bg-slate-100 rounded-full transition-colors">
                            <X className="w-6 h-6 text-slate-400" />
                        </button>
                    </div>

                    <form onSubmit={handleSubmit} className="space-y-6">
                        {/* File Upload Area */}
                        <div className="relative group">
                            <div className={`aspect-video rounded-3xl border-4 border-dashed transition-all overflow-hidden flex flex-col items-center justify-center gap-4 ${preview ? 'border-emerald-500' : 'border-slate-100 bg-slate-50 hover:border-emerald-300'}`}>
                                {preview ? (
                                    <>
                                        {fileType === 'video' ? (
                                            <video src={preview} className="w-full h-full object-cover" autoPlay muted loop />
                                        ) : (
                                            <img src={preview} alt="Preview" className="w-full h-full object-cover" />
                                        )}
                                        <div className="absolute inset-0 bg-slate-900/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                                            <label className="bg-white text-slate-900 px-6 py-3 rounded-xl font-bold cursor-pointer hover:bg-emerald-50 transition-colors flex items-center gap-2">
                                                <Upload className="w-5 h-5" /> Change File
                                                <input type="file" className="hidden" accept="image/*,video/*" onChange={handleFileChange} />
                                            </label>
                                        </div>
                                    </>
                                ) : (
                                    <label className="flex flex-col items-center cursor-pointer group">
                                        <div className="w-16 h-16 bg-white rounded-2xl flex items-center justify-center text-slate-400 group-hover:text-emerald-500 shadow-sm mb-2 transition-colors">
                                            <Upload className="w-8 h-8" />
                                        </div>
                                        <span className="text-slate-500 font-bold">Click to upload image or video</span>
                                        <span className="text-slate-400 text-xs font-medium">1920x1080 recommended</span>
                                        <input type="file" className="hidden" accept="image/*,video/*" onChange={handleFileChange} />
                                    </label>
                                )}
                            </div>
                        </div>

                        <div className="space-y-4">
                            <div>
                                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Main Heading / Title</label>
                                <div className="relative">
                                    <Type className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400" />
                                    <input 
                                        type="text"
                                        placeholder="e.g. Empower Your Future"
                                        className="w-full pl-12 pr-4 py-4 bg-slate-50 border-2 border-transparent focus:border-emerald-500 focus:bg-white rounded-2xl font-bold text-slate-900 transition-all outline-none"
                                        value={formData.title}
                                        onChange={(e) => setFormData({...formData, title: e.target.value})}
                                        required
                                    />
                                </div>
                            </div>

                            <div>
                                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Subtitle / Description</label>
                                <div className="relative">
                                    <AlignLeft className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400" />
                                    <input 
                                        type="text"
                                        placeholder="e.g. Join the best placement network in Kota"
                                        className="w-full pl-12 pr-4 py-4 bg-slate-50 border-2 border-transparent focus:border-emerald-500 focus:bg-white rounded-2xl font-bold text-slate-900 transition-all outline-none"
                                        value={formData.subtitle}
                                        onChange={(e) => setFormData({...formData, subtitle: e.target.value})}
                                    />
                                </div>
                            </div>

                            <div className="w-1/3">
                                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Display Order</label>
                                <div className="relative">
                                    <Hash className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400" />
                                    <input 
                                        type="number"
                                        className="w-full pl-12 pr-4 py-4 bg-slate-50 border-2 border-transparent focus:border-emerald-500 focus:bg-white rounded-2xl font-bold text-slate-900 transition-all outline-none"
                                        value={formData.order}
                                        onChange={(e) => setFormData({...formData, order: parseInt(e.target.value)})}
                                    />
                                </div>
                            </div>
                        </div>

                        <div className="flex gap-4 pt-4">
                            <button 
                                type="button" 
                                onClick={onClose}
                                className="flex-1 py-4 bg-slate-100 text-slate-500 font-black rounded-2xl hover:bg-slate-200 transition-all uppercase tracking-widest text-sm"
                            >
                                Cancel
                            </button>
                            <button 
                                type="submit"
                                className="flex-[2] py-4 bg-emerald-500 text-white font-black rounded-2xl hover:bg-emerald-600 transition-all shadow-lg shadow-emerald-500/20 uppercase tracking-widest text-sm"
                            >
                                Publish Slide
                            </button>
                        </div>
                    </form>
                </motion.div>
            </div>
        </AnimatePresence>
    );
};

export default CarouselModal;

import React, { useState, useEffect } from 'react';
import { useDispatch } from 'react-redux';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Briefcase, Mail, MapPin, DollarSign, GraduationCap, Clock, FileText, CheckCircle2 } from 'lucide-react';
import { createJob, updateJob } from '../../store/slices/jobsSlice';

const JobModal = ({ isOpen, onClose, job = null, isEditing = false }) => {
    const dispatch = useDispatch();
    const [formData, setFormData] = useState({
        title: '',
        companyName: '',
        location: '',
        salary: '',
        description: '',
        qualification: '',
        ageLimit: '',
        gender: 'Both',
        dutyTime: '',
        email: '',
        contactNumbers: '',
        profiles: '',
        customFields: [] // Array of { label: '', value: '' }
    });

    useEffect(() => {
        if (job && isEditing) {
            setFormData({
                title: job.title || '',
                companyName: job.companyName || '',
                location: job.location || '',
                salary: job.salary || '',
                description: job.description || '',
                qualification: job.qualification || '',
                ageLimit: job.ageLimit || '',
                gender: job.gender || 'Both',
                dutyTime: job.dutyTime || '',
                email: job.email || '',
                contactNumbers: job.contactNumbers || '',
                profiles: job.profiles || '',
                customFields: job.job_posting?.custom_fields ? Object.entries(job.job_posting.custom_fields).map(([label, value]) => ({ label, value })) : []
            });
        } else {
            setFormData({
                title: '',
                companyName: '',
                location: '',
                salary: '',
                description: '',
                qualification: '',
                ageLimit: '',
                gender: 'Both',
                dutyTime: '',
                email: '',
                contactNumbers: '',
                profiles: '',
                customFields: []
            });
        }
    }, [job, isEditing, isOpen]);

    const handleSubmit = (e) => {
        e.preventDefault();

        // Transform custom fields array to object
        const customFieldsObj = formData.customFields.reduce((acc, field) => {
            if (field.label.trim() && field.value.trim()) {
                acc[field.label.trim()] = field.value.trim();
            }
            return acc;
        }, {});

        const submissionData = {
            ...formData,
            job_posting: {
                ...job?.job_posting,
                custom_fields: customFieldsObj
            }
        };

        if (isEditing && job?._id) {
            dispatch(updateJob({ id: job._id, jobData: submissionData }));
        } else {
            dispatch(createJob(submissionData));
        }
        onClose();
    };

    const addCustomField = () => {
        setFormData({
            ...formData,
            customFields: [...formData.customFields, { label: '', value: '' }]
        });
    };

    const removeCustomField = (index) => {
        const newFields = [...formData.customFields];
        newFields.splice(index, 1);
        setFormData({ ...formData, customFields: newFields });
    };

    const handleCustomFieldChange = (index, field, value) => {
        const newFields = [...formData.customFields];
        newFields[index][field] = value;
        setFormData({ ...formData, customFields: newFields });
    };

    if (!isOpen) return null;

    return (
        <AnimatePresence>
            <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm overflow-y-auto">
                <motion.div 
                    initial={{ opacity: 0, scale: 0.95, y: 20 }}
                    animate={{ opacity: 1, scale: 1, y: 0 }}
                    exit={{ opacity: 0, scale: 0.95, y: 20 }}
                    className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-2xl my-8 overflow-hidden border border-slate-100 flex flex-col"
                >
                    {/* Header */}
                    <div className="p-8 border-b border-slate-100 flex justify-between items-center bg-slate-50">
                        <div className="flex items-center gap-4">
                            <div className="w-12 h-12 bg-emerald-500 rounded-2xl flex items-center justify-center shadow-lg shadow-emerald-500/20">
                                <Briefcase className="w-6 h-6 text-white" />
                            </div>
                            <div>
                                <h2 className="text-2xl font-black text-slate-800 uppercase tracking-tight">
                                    {isEditing ? 'Edit Job Posting' : 'Add New Job'}
                                </h2>
                                <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">Post a new career opportunity</p>
                            </div>
                        </div>
                        <button onClick={onClose} className="p-3 hover:bg-white rounded-full transition-all text-slate-400 hover:text-red-500 shadow-sm border border-transparent hover:border-slate-100">
                            <X className="w-6 h-6" />
                        </button>
                    </div>

                    <form onSubmit={handleSubmit} className="p-10 space-y-8 overflow-y-auto max-h-[70vh] custom-scrollbar">
                        {/* Section 1: Basic Info */}
                        <div className="space-y-6">
                            <h3 className="text-sm font-black text-emerald-600 uppercase tracking-[0.2em] flex items-center gap-2">
                                <FileText className="w-4 h-4" /> Basic Information
                            </h3>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                <div className="space-y-2">
                                    <label className="text-xs font-black uppercase tracking-widest text-slate-400 ml-1">Job Title</label>
                                    <div className="relative">
                                        <Briefcase className="absolute left-4 top-4 w-4 h-4 text-slate-300" />
                                        <input 
                                            className="w-full pl-12 pr-5 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-emerald-500 focus:bg-white transition-all outline-none font-bold text-slate-700"
                                            placeholder="e.g. Software Engineer"
                                            value={formData.title}
                                            onChange={(e) => setFormData({...formData, title: e.target.value})}
                                            required
                                        />
                                    </div>
                                </div>
                                <div className="space-y-2">
                                    <label className="text-xs font-black uppercase tracking-widest text-slate-400 ml-1">Company Name</label>
                                    <input 
                                        className="w-full px-5 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-emerald-500 focus:bg-white transition-all outline-none font-bold text-slate-700"
                                        placeholder="Company Name"
                                        value={formData.companyName}
                                        onChange={(e) => setFormData({...formData, companyName: e.target.value})}
                                        required
                                    />
                                </div>
                            </div>
                        </div>

                        {/* Section 2: Details */}
                        <div className="space-y-6">
                            <h3 className="text-sm font-black text-emerald-600 uppercase tracking-[0.2em] flex items-center gap-2">
                                <MapPin className="w-4 h-4" /> Location & Compensation
                            </h3>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                <div className="space-y-2">
                                    <label className="text-xs font-black uppercase tracking-widest text-slate-400 ml-1">Location</label>
                                    <div className="relative">
                                        <MapPin className="absolute left-4 top-4 w-4 h-4 text-slate-300" />
                                        <input 
                                            className="w-full pl-12 pr-5 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-emerald-500 focus:bg-white transition-all outline-none font-bold text-slate-700"
                                            placeholder="e.g. Remote, New Delhi"
                                            value={formData.location}
                                            onChange={(e) => setFormData({...formData, location: e.target.value})}
                                            required
                                        />
                                    </div>
                                </div>
                                <div className="space-y-2">
                                    <label className="text-xs font-black uppercase tracking-widest text-slate-400 ml-1">Salary Range</label>
                                    <div className="relative">
                                        <DollarSign className="absolute left-4 top-4 w-4 h-4 text-slate-300" />
                                        <input 
                                            className="w-full pl-12 pr-5 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-emerald-500 focus:bg-white transition-all outline-none font-bold text-slate-700"
                                            placeholder="e.g. 5-8 LPA"
                                            value={formData.salary}
                                            onChange={(e) => setFormData({...formData, salary: e.target.value})}
                                            required
                                        />
                                    </div>
                                </div>
                            </div>
                        </div>

                        {/* Section 3: Requirements */}
                        <div className="space-y-6">
                            <h3 className="text-sm font-black text-emerald-600 uppercase tracking-[0.2em] flex items-center gap-2">
                                <GraduationCap className="w-4 h-4" /> Requirements
                            </h3>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                <div className="space-y-2">
                                    <label className="text-xs font-black uppercase tracking-widest text-slate-400 ml-1">Qualification</label>
                                    <input 
                                        className="w-full px-5 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-emerald-500 focus:bg-white transition-all outline-none font-bold text-slate-700"
                                        placeholder="e.g. B.Tech, MBA"
                                        value={formData.qualification}
                                        onChange={(e) => setFormData({...formData, qualification: e.target.value})}
                                    />
                                </div>
                                <div className="space-y-2">
                                    <label className="text-xs font-black uppercase tracking-widest text-slate-400 ml-1">Age Limit</label>
                                    <input 
                                        className="w-full px-5 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-emerald-500 focus:bg-white transition-all outline-none font-bold text-slate-700"
                                        placeholder="e.g. 18-35"
                                        value={formData.ageLimit}
                                        onChange={(e) => setFormData({...formData, ageLimit: e.target.value})}
                                    />
                                </div>
                            </div>
                        </div>

                        {/* Section 4: Contact */}
                        <div className="space-y-6">
                            <h3 className="text-sm font-black text-emerald-600 uppercase tracking-[0.2em] flex items-center gap-2">
                                <Mail className="w-4 h-4" /> Contact Information
                            </h3>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                <div className="space-y-2">
                                    <label className="text-xs font-black uppercase tracking-widest text-slate-400 ml-1">Contact Email</label>
                                    <input 
                                        type="email"
                                        className="w-full px-5 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-emerald-500 focus:bg-white transition-all outline-none font-bold text-slate-700"
                                        placeholder="hr@company.com"
                                        value={formData.email}
                                        onChange={(e) => setFormData({...formData, email: e.target.value})}
                                        required
                                    />
                                </div>
                                <div className="space-y-2">
                                    <label className="text-xs font-black uppercase tracking-widest text-slate-400 ml-1">Phone Numbers</label>
                                    <input 
                                        className="w-full px-5 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-emerald-500 focus:bg-white transition-all outline-none font-bold text-slate-700"
                                        placeholder="Comma separated"
                                        value={formData.contactNumbers}
                                        onChange={(e) => setFormData({...formData, contactNumbers: e.target.value})}
                                    />
                                </div>
                            </div>
                        </div>

                        {/* Section 5: Job Profile Tags */}
                        <div className="space-y-2">
                            <label className="text-xs font-black uppercase tracking-widest text-slate-400 ml-1">Job Profile Tags</label>
                            <input 
                                className="w-full px-5 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-emerald-500 focus:bg-white transition-all outline-none font-bold text-slate-700"
                                placeholder="e.g. Mechanical, Kota, Urgent (Comma separated)"
                                value={formData.profiles}
                                onChange={(e) => setFormData({...formData, profiles: e.target.value})}
                            />
                        </div>

                        {/* Section 6: Description */}
                        <div className="space-y-2">
                            <label className="text-xs font-black uppercase tracking-widest text-slate-400 ml-1">Job Description</label>
                            <textarea 
                                className="w-full px-5 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-emerald-500 focus:bg-white transition-all outline-none font-bold text-slate-700 min-h-[150px]"
                                placeholder="Describe the job role and responsibilities..."
                                value={formData.description}
                                onChange={(e) => setFormData({...formData, description: e.target.value})}
                                required
                            />
                        </div>

                        <div className="h-px bg-slate-100 my-8"></div>

                        {/* Section 7: Custom Fields */}
                        <div className="space-y-6">
                            <div className="flex justify-between items-center">
                                <h3 className="text-sm font-black text-emerald-600 uppercase tracking-[0.2em] flex items-center gap-2">
                                    <Plus className="w-4 h-4" /> Custom Fields
                                </h3>
                                <button 
                                    type="button"
                                    onClick={addCustomField}
                                    className="text-[10px] font-black text-emerald-600 uppercase tracking-widest flex items-center gap-1 hover:text-emerald-700 transition-colors"
                                >
                                    <Plus className="w-3 h-3" /> Add Field
                                </button>
                            </div>

                            <div className="space-y-4">
                                {formData.customFields.map((field, index) => (
                                    <div key={index} className="grid grid-cols-1 md:grid-cols-7 gap-4 items-end bg-slate-50 p-4 rounded-2xl border border-slate-100">
                                        <div className="md:col-span-3 space-y-2">
