    const getImageUrl = (image) => {
        if (!image) return 'https://images.unsplash.com/photo-1594673752579-40993cf394c5?fit=crop&q=80&w=400';

        let url = image;
        if (typeof url === 'string' && url.includes('localhost:5000')) {
