                        <div className={`transition-opacity duration-500 ${paymentStatus === 'success' || isVerifying ? 'opacity-30 pointer-events-none' : 'opacity-100'}`}>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                <div className="space-y-2">
