import React, { useState, useEffect, useRef } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { Mail, Lock, User, ArrowRight, ShieldAlert, CheckCircle, XCircle } from 'lucide-react';
import { useSelector, useDispatch } from 'react-redux';
import { signup, googleLogin, reset, verifyRegistrationPayment, setSecretVerified } from '../store/slices/authSlice';
import { motion, AnimatePresence } from 'framer-motion';
import SmartButton from '../components/SmartButton';

const Signup = () => {
    const [name, setName] = useState('');
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [role, setRole] = useState('user');
    const [adminSecret, setAdminSecret] = useState('');
    const dispatch = useDispatch();
    const navigate = useNavigate();

    const { user, isLoading, isError, isSuccess, message } = useSelector((state) => state.auth);
    const [verificationStatus, setVerificationStatus] = useState(null); // 'success' | 'error' | null

    const VIP_EMAILS = ['hitkarikusum.ngo@gmail.com', 'khmbvs26@gmail.com'];
    const isVIPEmail = (email) => VIP_EMAILS.includes(email);

    // Native Google SDK Handler
    useEffect(() => {
        const handleGoogleAuth = (event) => {
            const credentialResponse = event.detail;
            console.log('Google Signup Success (Pure Native):', credentialResponse);
            if (credentialResponse.credential) {
                dispatch(googleLogin({ 
                    token: credentialResponse.credential, 
                    isAccessToken: false,
                    role,
                    adminSecret
                }));
            }
        };

        window.addEventListener('google-auth-success', handleGoogleAuth);

        // Render the button
        if (window.google) {
            google.accounts.id.renderButton(
                document.getElementById("google-button-native"),
                { theme: "outline", size: "large", width: "350", shape: "pill" }
            );
        }

        return () => window.removeEventListener('google-auth-success', handleGoogleAuth);
    }, [dispatch, role, adminSecret]);

    useEffect(() => {
        if (isSuccess && user) {
            navigate('/');
            // Small delay to ensure state isn't cleared too early if navigate is async
            setTimeout(() => dispatch(reset()), 100);
        }

        // Auto-detect admin if VIP email is detected
        if (isVIPEmail(email) && role !== 'admin') {
            setRole('admin');
            setAdminSecret('rcsplacements2009');
        }

        if (isError) {
            // Check if it's a role mismatch error
            if (message === 'You are a standard user and cannot access the admin panel.' || 
                message === 'Admins must login using the Admin account type.') {

                if (role === 'user') {
                    // Admin trying to signup as user
                    alert("You are an Admin! Please select 'Admin' account type to register.");
                    setRole('admin');
                    dispatch(reset());
                } else {
                    // User trying to signup as admin
                    alert("you are user login or signup as user only");
                    setRole('user');
                    dispatch(reset());
                }
            }

            const timer = setTimeout(() => {
                dispatch(reset());
            }, 3000);
            return () => clearTimeout(timer);
        }
    }, [user, isError, isSuccess, message, navigate, dispatch, email, role]);

    const handleVerifyAdmin = () => {
        if (adminSecret === 'rcsplacements2009') {
            setVerificationStatus('success');
        } else {
            setVerificationStatus('error');
            setTimeout(() => {
                setRole('user');
                setAdminSecret('');
                setVerificationStatus(null);
            }, 1500);
        }
    };

    const handleSubmit = async (e) => {
        if (e) e.preventDefault();

        // Admin verification guard
        if (role === 'admin' && verificationStatus !== 'success' && !isVIPEmail(email)) {
            alert('Verify First');
            return;
        }

        const resultAction = await dispatch(signup({ name, email, password, role, adminSecret }));

        if (signup.fulfilled.match(resultAction)) {
            navigate('/');
        }
    };

